package com.example.auth

import android.content.Context
import android.content.SharedPreferences
import androidx.annotation.MainThread
import androidx.annotation.WorkerThread

class AuthManager private constructor(
    private val prefs: SharedPreferences
) {
    companion object {
        private const val PREFS_NAME = "auth_prefs"
        private const val KEY_AUTH_TOKEN = "auth_token"
        private const val KEY_USER_ID = "user_id"
        private const val KEY_LOGGED_IN = "logged_in"

        @Volatile
        private var instance: AuthManager? = null

        fun getInstance(context: Context): AuthManager {
            val appContext = context.applicationContext
            return instance ?: synchronized(this) {
                instance ?: AuthManager(
                    appContext.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
                ).also { instance = it }
            }
        }
    }

    data class Session(
        val userId: String,
        val authToken: String
    )

    val isLoggedIn: Boolean
        get() = prefs.getBoolean(KEY_LOGGED_IN, false) &&
            !prefs.getString(KEY_USER_ID, null).isNullOrBlank() &&
            !prefs.getString(KEY_AUTH_TOKEN, null).isNullOrBlank()

    fun getUserIdOrNull(): String? = prefs.getString(KEY_USER_ID, null)

    fun getAuthTokenOrNull(): String? = prefs.getString(KEY_AUTH_TOKEN, null)

    fun getSessionOrNull(): Session? {
        if (!isLoggedIn) return null
        val userId = prefs.getString(KEY_USER_ID, null) ?: return null
        val token = prefs.getString(KEY_AUTH_TOKEN, null) ?: return null
        if (userId.isBlank() || token.isBlank()) return null
        return Session(userId = userId, authToken = token)
    }

    @MainThread
    fun saveLogin(userId: String, authToken: String) {
        prefs.edit()
            .putString(KEY_USER_ID, userId)
            .putString(KEY_AUTH_TOKEN, authToken)
            .putBoolean(KEY_LOGGED_IN, true)
            .apply()
    }

    @WorkerThread
    fun saveLoginSync(userId: String, authToken: String): Boolean {
        return prefs.edit()
            .putString(KEY_USER_ID, userId)
            .putString(KEY_AUTH_TOKEN, authToken)
            .putBoolean(KEY_LOGGED_IN, true)
            .commit()
    }

    @MainThread
    fun logout() {
        prefs.edit()
            .remove(KEY_USER_ID)
            .remove(KEY_AUTH_TOKEN)
            .putBoolean(KEY_LOGGED_IN, false)
            .apply()
    }

    @WorkerThread
    fun logoutSync(): Boolean {
        return prefs.edit()
            .remove(KEY_USER_ID)
            .remove(KEY_AUTH_TOKEN)
            .putBoolean(KEY_LOGGED_IN, false)
            .commit()
    }

    fun clearAll() {
        prefs.edit().clear().apply()
    }
}